'use strict';

import { NativeModules, NativeAppEventEmitter } from 'react-native';

const NativeCallDetector = NativeModules.RCTCallDetector || NativeModules.CallDetector;

if (NativeCallDetector && NativeCallDetector.startListener) {
  try {
    NativeCallDetector.startListener();
  } catch (err) {
    console.warn('Failed to start native call detector listener:', err);
  }
}

class CallDetector {
  static listeners = {};

  name;
  subscription;

  constructor(name, callback) {
    this.name = name;
    if (CallDetector.listeners[name]) {
      CallDetector.listeners[name].dispose();
    }
    CallDetector.listeners[name] = this;
    this.subscription = NativeAppEventEmitter.addListener('EventPhoneCallChange', callback);
  }

  dispose() {
    if (this.subscription) {
      this.subscription.remove();
    }
    delete CallDetector.listeners[this.name];
  }
}

export default CallDetector;
module.exports = CallDetector;